import { Component, OnInit } from '@angular/core';

@Component({
  selector: 'app-header',
  templateUrl: './header.component.html',
  styleUrls: ['./header.component.css']
})
export class HeaderComponent implements OnInit {
  isMenuOpen = false;

  constructor() { }

  ngOnInit(): void {
  }

  toggleMenu() {
    this.isMenuOpen = !this.isMenuOpen;
  }

  scrollToSection(sectionId: string) {
    this.isMenuOpen = false;
    const element = document.getElementById(sectionId);
    if (element) {
      element.scrollIntoView({ behavior: 'smooth' });
    }
  }

  scrollToTop() {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }
}
<header class="header">
  <div class="header-content">
    <div class="logo-container">
      <img src="assets/glumion-logo.png" alt="Glumion Logo" class="logo" (click)="scrollToTop()">
    </div>
    
    <button class="mobile-menu-toggle" (click)="toggleMenu()">
      <span class="menu-icon">☰</span>
    </button>

    <nav class="nav-items" [class.active]="isMenuOpen">
      <a class="nav-item" (click)="scrollToSection('hero')">Home</a>
      <a class="nav-item" (click)="scrollToSection('trailer')">Trailer</a>
      <a class="nav-item" (click)="scrollToSection('about')">About</a>
      <a class="nav-item" (click)="scrollToSection('download')">Download</a>
    </nav>
  </div>
</header>
